246	func singleHistoryUnit(metricID string, history []HistoryRecord) (string, error) {
247		var (
248			unit    string
249			seenSet = map[string]struct{}{}
250			seen    []string
251		)
252		for _, rec := range history {
253			if _, ok := seenSet[rec.Unit]; ok {
254				continue
255			}
256			seenSet[rec.Unit] = struct{}{}
257			seen = append(seen, rec.Unit)
258			if len(seen) == 1 {
259				unit = rec.Unit
260			}
261		}
262		if len(seen) <= 1 {
263			return unit, nil
264		}
265		units := make([]string, 0, len(seen))
266		for _, v := range seen {
267			if v == "" {
268				units = append(units, "(none)")
269				continue
270			}
271			units = append(units, v)
272		}
273		return "", fmt.Errorf("metric %q has mixed units: %s", metricID, strings.Join(units, ", "))
274	}
