27	func metricHistoryFromExec(rec ddxexec.RunRecord) (HistoryRecord, error) {
28		out := HistoryRecord{
29			RunID:        rec.RunID,
30			MetricID:     metricArtifactID(rec.ArtifactIDs),
31			DefinitionID: rec.DefinitionID,
32			ObservedAt:   rec.StartedAt,
33			Status:       StatusPass,
34			ExitCode:     rec.ExitCode,
35			DurationMS:   rec.FinishedAt.Sub(rec.StartedAt).Milliseconds(),
36			Stdout:       rec.Result.Stdout,
37			Stderr:       rec.Result.Stderr,
38			ArtifactID:   metricArtifactID(rec.ArtifactIDs),
39		}
40		if rec.Status != ddxexec.StatusSuccess {
41			out.Status = StatusFail
42		}
43		if rec.Result.Metric != nil {
44			out.Value = rec.Result.Metric.Value
45			out.Unit = rec.Result.Metric.Unit
46			out.Comparison = ComparisonResult{
47				Baseline:  rec.Result.Metric.Comparison.Baseline,
48				Delta:     rec.Result.Metric.Comparison.Delta,
49				Direction: rec.Result.Metric.Comparison.Direction,
50			}
51		}
52		return out, nil
53	}
